// Split the parsed outline into individual items — one per section + one for FAQs.
// n8n will send each item to Perplexity in parallel.
// Headings are NOT included in prompts — the Assemble node injects them.
const data = $input.first().json;
const sections = data.sections || [];
const faqs = data.faqs || [];
const keywords = data.target_keywords?.join(', ') || data.seo_enrichment?.keyword_suggestions?.slice(0,5).map(k => k.keyword).join(', ') || 'N/A';
const related = data.seo_enrichment?.related_searches?.join(', ') || 'N/A';
const paaQuestions = data.seo_enrichment?.people_also_ask?.map(p => p.question).filter(Boolean).join(', ') || 'N/A';
const editedPrompt = data.edited_prompt || null;
const reviewId = data.review_id || null;
const items = [];

for (let i = 0; i < sections.length; i++) {
  const s = sections[i];
  items.push({
    json: {
      section_index: i,
      section_type: 'section',
      heading: s.heading,
      prompt: `Document title: "${data.title}"\nPrimary topic: ${data.topic}\nSection heading: ${s.heading}\nSection description: ${s.description || 'N/A'}\n\nTarget keywords: ${keywords}\nRelated topics: ${related}\nCommon user questions: ${paaQuestions}\n\nWrite the body content for this section only. Do not include headings.`,
      id: data.id,
      topic: data.topic,
      category: data.category,
      title: data.title,
      seo_enrichment: data.seo_enrichment,
      target_keywords: data.target_keywords,
      edited_prompt: editedPrompt,
      review_id: reviewId
    }
  });
}

const faqSystemPrompt = `You are a subject-matter explainer writing factual, neutral FAQ content for a fintech AI assistant.\n\nFor each question provided, write a clear and thorough answer.\n\nOutput rules:\n- Use ### before each question as a sub-heading, copying the question text exactly\n- Write the answer as one or more paragraphs immediately after the heading\n- Use markdown formatting (bold for key terms where helpful)\n- Tone: neutral, educational, authoritative\n- Do NOT mention any brands or competitors — including Stripe, Checkout, Nuvie, Mollie, Worldpay, Trust Payments, GoCardless, PayPoint, Barclaycard Payments, Lloyds Cardnet, Opayo, DNA Payments, Cashflows, takepayments, Elavon UK\n- No preamble or closing statements`;

if (faqs.length > 0) {
  const faqList = faqs.map((f, i) => `${i+1}. ${f.question}`).join('\n');
  items.push({
    json: {
      section_index: sections.length,
      section_type: 'faqs',
      heading: 'Frequently Asked Questions',
      prompt: `Document title: "${data.title}"\nPrimary topic: ${data.topic}\n\nAnswer each of these questions thoroughly:\n${faqList}\n\nUse ### before each question as a sub-heading. Provide clear, accurate answers.`,
      id: data.id,
      topic: data.topic,
      category: data.category,
      title: data.title,
      seo_enrichment: data.seo_enrichment,
      target_keywords: data.target_keywords,
      edited_prompt: faqSystemPrompt,
      review_id: reviewId
    }
  });
}

return items;

// Filter for queued topics only
const allItems = $input.all();
const queuedItems = allItems.filter(item => item.json.status === 'Queued');
return queuedItems;

// Merge keyword suggestions and People Also Ask data
const topicData = $('Update Status → In Progress').first().json;
const keywordResponse = $('DataforSEO: Keyword Suggestions1').first().json;
const paaResponse = $('DataforSEO: People Also Ask').first().json;

// Extract keyword suggestions (Google Ads Keywords Data API format)
let keywords = [];
try {
  const keywordItems = keywordResponse?.tasks?.[0]?.result?.[0]?.items || [];
  keywords = keywordItems
    .slice(0, 15)
    .map(item => ({
      keyword: item.keyword,
      search_volume: item.search_volume || item.keyword_info?.search_volume || 0,
      competition: item.competition || item.keyword_info?.competition || 'unknown',
      cpc: item.cpc || item.keyword_info?.cpc || 0
    }))
    .sort((a, b) => b.search_volume - a.search_volume);
} catch (e) {
  console.log('Error parsing keywords:', e.message);
}

// Extract People Also Ask questions
let peopleAlsoAsk = [];
try {
  const serpItems = paaResponse?.tasks?.[0]?.result?.[0]?.items || [];
  const paaItems = serpItems.filter(item => item.type === 'people_also_ask');

  for (const paa of paaItems) {
    if (paa.items) {
      for (const q of paa.items.slice(0, 8)) {
        peopleAlsoAsk.push({
          question: q.title || q.question,
          answer_snippet: q.snippet || null
        });
      }
    }
  }
} catch (e) {
  console.log('Error parsing PAA:', e.message);
}

// Extract related searches if available
let relatedSearches = [];
try {
  const serpItems = paaResponse?.tasks?.[0]?.result?.[0]?.items || [];
  const relatedItems = serpItems.filter(item => item.type === 'related_searches');

  for (const related of relatedItems) {
    if (related.items) {
      relatedSearches = related.items.slice(0, 10).map(r => r.title || r.query);
    }
  }
} catch (e) {
  console.log('Error parsing related searches:', e.message);
}

return [{
  json: {
    ...topicData,
    seo_enrichment: {
      keyword_suggestions: keywords,
      people_also_ask: peopleAlsoAsk,
      related_searches: relatedSearches
    }
  }
}];

// Parse the GPT response and extract JSON outline with SEO data
const response = $input.first().json;
const enrichedData = $('Merge SEO Enrichment Data').first().json;

let outline;
try {
  // Try to parse the response content
  const content = response.message?.content || response.choices?.[0]?.message?.content || JSON.stringify(response);
  // Extract JSON from response (handle markdown code blocks)
  const jsonMatch = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/\{[\s\S]*\}/);
  outline = JSON.parse(jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : content);
} catch (e) {
  // Fallback outline using SEO data
  const paaQuestions = enrichedData.seo_enrichment?.people_also_ask || [];
  outline = {
    title: enrichedData.topic,
    sections: [{ heading: 'Overview', description: 'Main content' }],
    faqs: paaQuestions.map(p => ({ question: p.question })),
    target_keywords: []
  };
}

return [{
  json: {
    ...enrichedData,
    outline: outline,
    title: outline.title || enrichedData.topic,
    sections: outline.sections || [],
    faqs: outline.faqs || [],
    target_keywords: outline.target_keywords || []
  }
}];

// Parse Claude response — expects Markdown content followed by ---FACT-CHECK--- separator.
// Falls back to legacy JSON format if separator not found (handles re-runs of older content).
const allItems = $input.all();
const perplexityItems = $('Generate Content (Perplexity)').all();
const results = [];

const SEPARATOR = '---FACT-CHECK---';

for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];
  const raw = item.json.choices?.[0]?.message?.content || '';

  let content = raw;
  let analysis = '(No analysis provided)';

  if (raw.includes(SEPARATOR)) {
    const parts = raw.split(SEPARATOR);
    content = parts[0].trim();
    analysis = parts.slice(1).join(SEPARATOR).trim() || '(No analysis provided)';
  } else {
    // Fallback: try legacy JSON format
    try {
      let jsonStr = raw.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/m, '').trim();
      const parsed = JSON.parse(jsonStr);
      if (typeof parsed.content === 'string') {
        content = parsed.content;
        analysis = parsed.analysis || '(No analysis provided)';
      }
    } catch (e) {
      content = raw;
      analysis = '(Analysis not available)';
    }
  }

  const citations = perplexityItems[i]?.json?.citations || [];

  results.push({
    json: {
      ...item.json,
      choices: [{ message: { content } }],
      fact_check_analysis: analysis,
      citations: citations
    }
  });
}

return results;

// Assemble the final markdown document from parallel Claude-validated responses.
// Each input item is one section's validated response (items arrive in order).
// Headings are injected here so the system prompt can produce clean body text.
// Citations are preserved here and stripped only after GoToHuman approval.
const allItems = $input.all();
const topicData = $('Parse Outline JSON').first().json;
const splitItems = $('Split Sections').all();

// Helper: clean formatting only — citation markers [1][2] are preserved for reviewer.
// Citations are stripped from the final output only after GoToHuman approval.
function cleanFormatting(text) {
  return text.replace(/ {2,}/g, ' ').replace(/\u2014/g, ' - ').replace(/\u2013/g, ' - ');
}

const title = topicData.title || topicData.topic;
let md = `# ${title}\n\n`;
let analysisReport = `## Fact-Check Analysis & Citation Report\n\n**Document:** ${title}\n\n`;

// Merge each section's generated content in order
for (let i = 0; i < allItems.length; i++) {
  const heading = splitItems[i]?.json?.heading || `Section ${i + 1}`;
  const sectionType = splitItems[i]?.json?.section_type || 'section';
  try {
    const rawContent = allItems[i].json.choices?.[0]?.message?.content || '';
    const content = cleanFormatting(rawContent);
    if (content) {
      // Inject the section heading before the body text
      if (sectionType === 'faqs') {
        md += `## Frequently Asked Questions\n\n` + content.trim() + '\n\n';
      } else {
        md += `## ${heading}\n\n` + content.trim() + '\n\n';
      }
    } else {
      md += `## ${heading}\n\nContent pending.\n\n`;
    }
    // Append section fact-check analysis
    const sectionAnalysis = allItems[i].json.fact_check_analysis || '';
    if (sectionAnalysis) {
      analysisReport += `### ${heading}\n\n${sectionAnalysis.trim()}\n\n`;
    }
    // Append Perplexity source URLs for this section
    const sectionCitations = allItems[i].json.citations || [];
    if (sectionCitations.length > 0) {
      analysisReport += '**Source URLs:**\n';
      sectionCitations.forEach((url, idx) => {
        analysisReport += `- [${idx + 1}] ${url}\n`;
      });
      analysisReport += '\n';
    }
  } catch (e) {
    md += `## ${heading}\n\nContent generation failed.\n\n`;
  }
}

// Add SEO metadata section
const seoData = topicData.seo_enrichment || {};
if (seoData.keyword_suggestions?.length || seoData.related_searches?.length) {
  md += '---\n\n## SEO Metadata\n\n';
  if (topicData.target_keywords?.length) {
    md += `**Target Keywords:** ${topicData.target_keywords.join(', ')}\n\n`;
  }
  if (seoData.keyword_suggestions?.length) {
    md += '**Related Keywords:**\n';
    for (const kw of seoData.keyword_suggestions.slice(0, 10)) {
      md += `- ${kw.keyword} (Search Vol: ${kw.search_volume})\n`;
    }
    md += '\n';
  }
  if (seoData.related_searches?.length) {
    md += `**Related Searches:** ${seoData.related_searches.join(', ')}\n\n`;
  }
}

md += `---\n\n*Generated on ${new Date().toISOString().split('T')[0]}*\n`;

// Final cleanup: remove any remaining em/en dashes from the entire document
md = md.replace(/\u2014/g, ' - ').replace(/\u2013/g, ' - ');

// Pass through retry fields from Split Sections (null on original flow, populated on retry)
const firstSplit = splitItems[0]?.json || {};

return [{
  json: {
    id: topicData.id,
    topic: topicData.topic,
    category: topicData.category,
    title: title,
    draft_markdown: md,
    fact_check_report: analysisReport,
    seo_enrichment: seoData,
    edited_prompt: firstSplit.edited_prompt || null,
    review_id: firstSplit.review_id || null
  }
}];

// Convert markdown content to binary for file upload
const data = $input.first().json;
const markdown = data.approved_content || data.content || "";
const topicId = data.id || data.topic_id;

// Create binary data from markdown string
const binaryData = Buffer.from(markdown, 'utf-8');

return [{
  json: {
    topic_id: topicId
  },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'text/markdown',
      fileName: `topic_${topicId}.md`
    }
  }
}];

// Extract the edited prompt and review ID from the GoToHuman retry webhook.
// Output the same structure as Parse Outline JSON so Split Sections can consume it,
// with added edited_prompt and review_id fields for the retry path.
const editedPrompt = $json.messages?.[0]?.content || '';
const reviewId = $json.reviewId || '';

// Get the original outline data from the earlier execution
const outlineData = $('Parse Outline JSON').first().json;

return [{
  json: {
    ...outlineData,
    edited_prompt: editedPrompt,
    review_id: reviewId
  }
}];
